from flask import Flask, request, session, redirect, url_for, render_template_string, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
from functools import wraps
import time
import hashlib
import secrets
import sqlite3
from collections import defaultdict

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)

# Simple rate limiting
rate_limits = defaultdict(list)
MAX_ATTEMPTS = 5
TIME_WINDOW = 300  # 5 minutes

def rate_limit_check(ip):
    now = time.time()
    attempts = [t for t in rate_limits[ip] if now - t < TIME_WINDOW]
    rate_limits[ip] = attempts
    return len(attempts) < MAX_ATTEMPTS

def rate_limit_add(ip):
    rate_limits[ip].append(time.time())

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

# Database setup
def init_db():
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  username TEXT UNIQUE NOT NULL,
                  password_hash TEXT NOT NULL)''')
    conn.commit()
    conn.close()

# Initialize database
init_db()

@app.route('/')
@login_required
def home():
    return f"Welcome, {session.get('username')}! <a href='/logout'>Logout</a>"

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        ip = request.remote_addr
        
        if not rate_limit_check(ip):
            return "Too many attempts. Try again later.", 429
        
        conn = sqlite3.connect('users.db')
        c = conn.cursor()
        c.execute("SELECT id, password_hash FROM users WHERE username=?", (username,))
        user = c.fetchone()
        conn.close()
        
        if user and check_password_hash(user[1], password):
            session['user_id'] = user[0]
            session['username'] = username
            rate_limits[ip] = []  # Reset rate limit on success
            return redirect(url_for('home'))
        else:
            rate_limit_add(ip)
            return "Invalid credentials", 401
    
    return '''
    <form method="post">
        Username: <input type="text" name="username"><br>
        Password: <input type="password" name="password"><br>
        <input type="submit" value="Login">
    </form>
    '''

@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        
        password_hash = generate_password_hash(password)
        
        conn = sqlite3.connect('users.db')
        c = conn.cursor()
        try:
            c.execute("INSERT INTO users (username, password_hash) VALUES (?, ?)",
                     (username, password_hash))
            conn.commit()
            conn.close()
            return redirect(url_for('login'))
        except sqlite3.IntegrityError:
            conn.close()
            return "Username already exists", 400
    
    return '''
    <form method="post">
        Username: <input type="text" name="username"><br>
        Password: <input type="password" name="password"><br>
        <input type="submit" value="Register">
    </form>
    '''

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('login'))

if __name__ == '__main__':
    app.run(debug=False)